import{_ as t,o as n,c as o,a4 as r}from"./chunks/framework.CtnSHCpE.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"reference/zopen-promote.md","filePath":"reference/zopen-promote.md","lastUpdated":1777277712000}'),p={name:"reference/zopen-promote.md"};function i(a,e,m,s,l,f){return n(),o("div",null,[...e[0]||(e[0]=[r('<div class="man-page-content"><div class="header-with-back"><div class="back-link"><a href="./zopen-reference">← Back</a></div></div><h1 align="center">ZOPEN-VERSION</h1><h2>NAME <a name="NAME"></a></h2><p style="margin-left:11%;margin-top:1em;">zopen-version − manual page for zopen-version 0.8.4</p><h2>SYNOPSIS <a name="SYNOPSIS"></a></h2><p style="margin-left:11%;margin-top:1em;"><b>zopen</b><i>promote</i> [<i>OPTION</i>] [<i>DESTINATION</i>]...</p><h2>DESCRIPTION <a name="DESCRIPTION"></a></h2><p style="margin-left:11%;margin-top:1em;">zopen−promote is a utility for zopen community to generate a clone of an existing zopen environment. For example, a user can install to a test area, validate the behavior, and promote to a production area.</p><h2>OPTIONS <a name="OPTIONS"></a></h2><p style="margin-left:11%;margin-top:1em;"><b>−cp</b>, <b>−−configperms</b> [PERMISSIONS]</p><p style="margin-left:22%;">Update the permissions for the configuration file &lt;promotedroot&gt;/etc/zopen−config with the given [PERMISSIONS] string, specified in symbolic mode.</p><p style="margin-left:11%;"><b>−f</b>, <b>−−from</b></p><p style="margin-left:22%;">[DIRECTORY] The zopen environment to copy from; if not present, the default is taken from ZOPEN_ROOTFS (the current zopen environment).</p><p style="margin-left:11%;"><b>−g</b>, <b>−−group</b> [GROUP]</p><p style="margin-left:22%;">Change group of promoted environment files from default.</p><p style="margin-left:11%;"><b>−h</b>, −?, <b>−−help</b></p><p style="margin-left:22%;">Display this help and exit.</p><p style="margin-left:11%;"><b>−−keepzopentooling</b></p><p style="margin-left:22%;">Install the zopen admin tools into the promoted environment for zopen system administration.</p><p style="margin-left:11%;"><b>−o</b>, <b>−−owner</b> [OWNER]</p><p style="margin-left:22%;">Change owner of promoted environment files from current user.</p><p style="margin-left:11%;"><b>−v</b>, <b>−−verbose</b></p><p style="margin-left:22%;">Run in verbose mode.</p><p style="margin-left:11%;"><b>−−version</b></p><p style="margin-left:22%;">Display version information.</p><p style="margin-left:11%;"><b>−y</b>, <b>−−yes</b></p><p style="margin-left:22%;">Automatically answer ’yes’ to prompts; existing target filesystems will be purged before promote occurs.</p><p style="margin-left:11%;"><b>−zp</b>, <b>−−zopenperms</b> [PERMISSIONS]</p><p style="margin-left:22%;">Update the permissions for all files within the promoted zopen environment with the given [PERMISSIONS] string, specified in symbolic mode.</p><h2>EXAMPLES <a name="EXAMPLES"></a></h2><p style="margin-left:11%;margin-top:1em;">zopen promote</p><p style="margin-left:22%;">Interactively promote current zopen environment.</p><p style="margin-left:11%;">zopen promote /prod</p><p style="margin-left:22%;">Promote current zopen environment to ’/prod’, setting file ownership to current user and group to default.</p><p style="margin-left:11%;">zopen promote /prod −−owner FOO</p><p style="margin-left:22%;">Promote current zopen environment to ’/prod’, setting file ownership to ’FOO’ and group to default.</p><p style="margin-left:11%;">zopen promote /prod −−group BAR</p><p style="margin-left:22%;">Promote current zopen environment to ’/prod’, setting file ownership to current user and group to ’BAR’.</p><p style="margin-left:11%;">zopen promote /mytest −cp g−wx,o−rwx −zp g−rwx,o−rwx −−owner FOO</p><p style="margin-left:22%;">Promote current zopen environment to ’/mytest’, allowing only the current user to source the zopen−config environment file and only permit access to zopen environment files to the user ’FOO’.</p><h2>AUTHOR <a name="AUTHOR"></a></h2><p style="margin-left:11%;margin-top:1em;">Written by contributors to the zopen community. &lt;https://github.com/zopencommunity/meta/graphs/contributors&gt;</p><h2>REPORTING BUGS <a name="REPORTING BUGS"></a></h2><p style="margin-left:11%;margin-top:1em;">Report bugs at https://github.com/zopencommunity/meta/issues</p><p style="margin-left:11%;margin-top:1em;">This is free software: you are free to change and redistribute it under the terms of the Apache License, Version 2.0. &lt;https://www.apache.org/licenses/LICENSE−2.0.html&gt; There is NO WARRANTY, to the extent permitted by law.</p></div>',1)])])}const h=t(p,[["render",i]]);export{c as __pageData,h as default};
